INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (1000, 3000, 2, 1, "調子が上がって\nきたなっ", "訓練はまだ\nここからですわ", "vo_minigame_1013_icon_1_002_001", 2, 2, "vo_minigame_1013_icon_2_002_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (5000, 3000, 2, 2, "ほらほら、\nまだいけるだろ？", "クスクス、悪くない\n流れですわね", "vo_minigame_1013_icon_1_003_001", 2, 2, "vo_minigame_1013_icon_2_003_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (10000, 3000, 3, 3, "へへっ、おまえら\nやるじゃねえか！", "すばらしい\n記録ですわ", "vo_minigame_1013_icon_1_004_001", 2, 2, "vo_minigame_1013_icon_2_004_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (10000, 3000, 3, 4, "あたしたちはまだ\n止まらねえぜ！", "乗りに乗って\nいますわね", "vo_minigame_1013_icon_1_005_001", 2, 3, "vo_minigame_1013_icon_2_005_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (10000, 3000, 3, 5, "見てろよ！\nマコト班の快進撃だ！", "まだまだ行きます\nついてきなさい", "vo_minigame_1013_icon_1_005_002", 2, 3, "vo_minigame_1013_icon_2_005_002");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (10000, 3000, 3, 6, "うおぉぉっ！\n絶好調だぜ！", "エリコ班の\n本領発揮ですわ！", "vo_minigame_1013_icon_1_005_003", 2, 3, "vo_minigame_1013_icon_2_005_003");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (0, 3000, 3, 7, "どこまで行けるか\n楽しみだなっ！", "ここからは\n前人未到の領域です！", "vo_minigame_1013_icon_1_006_001", 2, 4, "vo_minigame_1013_icon_2_006_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (1, 1000, 4, 8, "まだ諦めんなよっ", "厄介でしたわ…", "vo_minigame_1013_icon_1_007_001", 3, 5, "vo_minigame_1013_icon_2_007_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (1, 1000, 4, 9, "冷やっとしたぜ…！", "油断大敵です", "vo_minigame_1013_icon_1_007_002", 3, 5, "vo_minigame_1013_icon_2_007_002");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (1, 1000, 4, 10, "弱音を吐くなっ", "忌々しいっ…", "vo_minigame_1013_icon_1_007_003", 3, 5, "vo_minigame_1013_icon_2_007_003");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (99, 1500, 3, 11, "マコト班集合！", "大所帯ですわね", "vo_minigame_1013_icon_1_008_001", 4, 6, "vo_minigame_1013_icon_2_008_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (99, 1500, 3, 12, "連携してくぞ！", "エリコ班へようこそ", "vo_minigame_1013_icon_1_008_002", 4, 6, "vo_minigame_1013_icon_2_008_002");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (0, 3000, 6, 13, "みんなに力を！", "ナナカちゃんに\nお任せあれ", "vo_minigame_1013_icon_1_020_001", 1, 8, "vo_minigame_1013_icon_2_020_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (0, 3000, 7, 14, "任せてくれたまえ", "はっはっは！\n任せろ！", "vo_minigame_1013_icon_1_022_001", 1, 9, "vo_minigame_1013_icon_2_022_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (0, 3000, 8, 15, "ほな、いきまひょか", "どんどんいくわよ", "vo_minigame_1013_icon_1_023_001", 1, 10, "vo_minigame_1013_icon_2_023_001");
